1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const PROCESSING_FEE = 5;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	};
20	
21	function basePremium(item: any): number {
22	  return BASE_PREMIUMS[item.type] ?? 0;
23	}
24	
25	const COMPONENT_TYPES = ["rune", "moonstone"];
26	const BLOCK_SIZE = 3;
27	const BLOCK_PREMIUM = 60;
28	
29	export function claimOffice(input: any): unknown {
30	  const results = [];
31	  for (const step of input.steps) {
32	    validateItemTypes(step.items);
33	    let premium = PROCESSING_FEE;
34	
35	    const components = step.items.filter((i: any) => COMPONENT_TYPES.includes(i.type));
36	    const nonComponents = step.items.filter((i: any) => !COMPONENT_TYPES.includes(i.type));
37	
38	    for (const item of nonComponents) {
39	      premium += basePremium(item);
40	    }
41	
42	    if (components.length === BLOCK_SIZE && components.every((c: any) => c.type === components[0].type)) {
43	      premium += BLOCK_PREMIUM;
44	    } else {
45	      for (const item of components) {
46	        premium += basePremium(item);
47	      }
48	    }
49	
50	    results.push({ premium });
51	  }
52	  return { results };
53	}
